  "keystrokes": "python3 - <<'PY'
import re
f=open('/tmp/orig_intel.asm').read().split('\n')
funcs={'sky_color':(0x1b4d,0x1c8d),'plane_intersect':(0x19e5,0x1b4d),'sphere_intersect':(0x16c4,0x19e5),'trace':(0x1d5c,0x2203),'main':(0x2530,0x2c30)}
for name,(start,end) in funcs.items():
    print(f'=== {name} ===')
    for line in f:
        m=re.match(r'\s*([0-9a-f]+):',line)
        if m and start<=int(m.group(1),16)<end:
            # print compact
            print(line)
    print()
